import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { VerificationService } from '../verification.service';

@Component({
  selector: 'app-pre-invest-dashboard',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './pre-invest-dashboard.component.html',
  styleUrls: ['./pre-invest-dashboard.component.css']
})
export class PreInvestDashboardComponent implements OnInit {
  // Audit Check
  checkTitleNumber: string = '';
  isAudited: boolean = false;
  auditError: string = '';
  isSearchingAudit: boolean = false;

  // Simulator Data
  surface: number = 1000;
  landValuePerM2: number = 25000; // XAF
  titlingCostPerM2: number = 5000; // XAF

  repaymentModel: 'LAND_PORTION' | 'SALE_COMMISSION' = 'LAND_PORTION';
  portionPercentage: number = 25;

  simulationResults: any = null;

  constructor(private verificationService: VerificationService) {}

  ngOnInit() {
    this.runSimulation();
  }

  verifyAuditBeforeInvest() {
    if (!this.checkTitleNumber) return;
    this.isSearchingAudit = true;
    this.auditError = '';

    this.verificationService.getPropertyStatus(this.checkTitleNumber).subscribe({
      next: (property) => {
        this.isSearchingAudit = false;
        if (property.currentStatus === 'GREEN') {
          this.isAudited = true;
          this.runSimulation();
        } else {
          this.auditError = 'Le terrain présente des risques (Statut non VERT). Financement impossible.';
        }
      },
      error: () => {
        this.isSearchingAudit = false;
        this.auditError = 'Aucun audit "VÉRIFIER" trouvé. Vous devez d\'abord auditer ce titre.';
      }
    });
  }

  runSimulation() {
    const totalCurrentValue = this.surface * this.landValuePerM2;
    const totalTitlingCost = this.surface * this.titlingCostPerM2;

    const valueMultiplier = 3;
    const totalTitledValue = totalCurrentValue * valueMultiplier;

    let maTerreShare = 0;
    let ownerShare = 0;

    if (this.repaymentModel === 'LAND_PORTION') {
      maTerreShare = (this.portionPercentage / 100) * totalTitledValue;
      ownerShare = totalTitledValue - maTerreShare;
    } else {
      maTerreShare = totalTitlingCost + (totalTitledValue * 0.15);
      ownerShare = totalTitledValue - maTerreShare;
    }

    this.simulationResults = {
      totalCurrentValue,
      totalTitlingCost,
      totalTitledValue,
      maTerreShare,
      ownerShare,
      netGain: ownerShare - totalCurrentValue
    };
  }

  formatCurrency(amount: number): string {
    return new Intl.NumberFormat('fr-CM', { style: 'currency', currency: 'XAF' }).format(amount);
  }
}
<div class="pre-invest-dashboard">
  <div class="header-section" style="margin-bottom: 2rem;">
    <h2>PRÉ-INVESTIR - Le Levier Financier</h2>
    <p>maTerre finance votre titre foncier. Vous ne payez rien jusqu'à l'obtention du titre.</p>
  </div>

  <!-- STEP 1: Audit Check -->
  <div *ngIf="!isAudited" class="card" style="border-top: 5px solid var(--mt-red);">
    <h3>Audit de Sécurité Requis</h3>
    <p>Pour protéger son investissement, maTerre ne finance que les terrains ayant reçu un verdict <strong>VERT</strong> via le module <strong>VÉRIFIER</strong>.</p>
    
    <div style="display: flex; gap: 10px; margin-top: 2rem;">
      <input type="text" [(ngModel)]="checkTitleNumber" placeholder="N° de Titre Foncier (Ex: Vol 123 Fol 45)" style="flex: 1; padding: 12px; border: 1px solid #ccc; border-radius: 4px;">
      <button (click)="verifyAuditBeforeInvest()" [disabled]="isSearchingAudit || !checkTitleNumber" class="btn-primary">
        {{ isSearchingAudit ? 'Vérification...' : 'Vérifier l\'éligibilité' }}
      </button>
    </div>

    <p *ngIf="auditError" style="color: var(--mt-red); margin-top: 1rem; font-weight: bold;">{{ auditError }}</p>
    
    <div style="margin-top: 2rem; padding-top: 1rem; border-top: 1px solid #eee;">
      <p style="font-size: 0.9rem;">Vous n'avez pas encore audité votre terrain ?</p>
      <button class="btn-primary" style="background: white; color: var(--mt-green); border: 1px solid var(--mt-green);">Lancer un Audit Express (48h)</button>
    </div>
  </div>

  <!-- STEP 2: Simulator (Only if Audited) -->
  <div *ngIf="isAudited" class="card" style="border-top: 5px solid var(--mt-gold);">
    <div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 1rem;">
      <h3>Simulateur de Financement</h3>
      <span style="background: var(--mt-green); color: white; padding: 5px 10px; border-radius: 4px; font-size: 0.7rem; font-weight: bold;">ÉLIGIBLE AU FINANCEMENT ✅</span>
    </div>
    <p style="font-size: 0.9rem; color: #666; margin-bottom: 2rem;">Titre foncier audité : <strong>{{ checkTitleNumber }}</strong></p>

    <div style="display: grid; gap: 1.5rem; margin-bottom: 2rem;">
      <div>
        <label style="display: block; font-weight: bold; margin-bottom: 5px;">Surface du terrain (m²)</label>
        <input type="range" min="200" max="5000" step="100" [(ngModel)]="surface" (input)="runSimulation()" style="width: 100%; accent-color: var(--mt-green);">
        <p style="text-align: right; font-weight: bold;">{{ surface }} m²</p>
      </div>

      <div>
        <label style="display: block; font-weight: bold; margin-bottom: 5px;">Modèle de Remboursement</label>
        <div style="display: flex; gap: 10px;">
          <button (click)="repaymentModel = 'LAND_PORTION'; runSimulation()" 
                  [style.background]="repaymentModel === 'LAND_PORTION' ? 'var(--mt-green)' : 'white'"
                  [style.color]="repaymentModel === 'LAND_PORTION' ? 'white' : 'var(--mt-green)'"
                  style="flex: 1; padding: 10px; border: 1px solid var(--mt-green); border-radius: 4px; font-weight: bold; cursor: pointer;">
            Part de Terrain
          </button>
          <button (click)="repaymentModel = 'SALE_COMMISSION'; runSimulation()" 
                  [style.background]="repaymentModel === 'SALE_COMMISSION' ? 'var(--mt-green)' : 'white'"
                  [style.color]="repaymentModel === 'SALE_COMMISSION' ? 'white' : 'var(--mt-green)'"
                  style="flex: 1; padding: 10px; border: 1px solid var(--mt-green); border-radius: 4px; font-weight: bold; cursor: pointer;">
            Com. sur Vente
          </button>
        </div>
      </div>

      <div *ngIf="repaymentModel === 'LAND_PORTION'">
        <label style="display: block; font-weight: bold; margin-bottom: 5px;">Portion cédée à maTerre (%)</label>
        <input type="range" min="10" max="40" step="5" [(ngModel)]="portionPercentage" (input)="runSimulation()" style="width: 100%; accent-color: var(--mt-gold);">
        <p style="text-align: right; font-weight: bold;">{{ portionPercentage }} %</p>
      </div>
    </div>

    <!-- Results Display -->
    <div *ngIf="simulationResults" style="display: grid; grid-template-columns: 1fr 1fr; gap: 1rem; border-top: 1px solid #eee; padding-top: 1.5rem;">
      <div class="card" style="background: #f9f9f9; padding: 1rem; margin: 0;">
        <p style="font-size: 0.7rem; color: #888; margin: 0;">VALEUR SANS TITRE (Estimation)</p>
        <p style="font-size: 1.1rem; font-weight: bold; margin: 5px 0 0 0;">{{ formatCurrency(simulationResults.totalCurrentValue) }}</p>
      </div>
      <div class="card" style="background: #e8f5e9; padding: 1rem; margin: 0; border-left: 4px solid var(--mt-green);">
        <p style="font-size: 0.7rem; color: var(--mt-green); margin: 0;">VALEUR APRÈS TITRAGE</p>
        <p style="font-size: 1.1rem; font-weight: bold; margin: 5px 0 0 0; color: var(--mt-green);">{{ formatCurrency(simulationResults.totalTitledValue) }}</p>
      </div>
      <div class="card" style="background: #fff8e1; padding: 1rem; margin: 0; border-left: 4px solid var(--mt-gold);">
        <p style="font-size: 0.7rem; color: #c5a000; margin: 0;">INVESTISSEMENT maTerre (Frais + Commission)</p>
        <p style="font-size: 1.1rem; font-weight: bold; margin: 5px 0 0 0; color: #c5a000;">{{ formatCurrency(simulationResults.maTerreShare) }}</p>
      </div>
      <div class="card" style="background: var(--mt-green); padding: 1rem; margin: 0; color: white;">
        <p style="font-size: 0.7rem; color: rgba(255,255,255,0.7); margin: 0;">VOTRE GAIN NET FINAL</p>
        <p style="font-size: 1.1rem; font-weight: bold; margin: 5px 0 0 0;">{{ formatCurrency(simulationResults.ownerShare) }}</p>
      </div>
    </div>

    <div style="margin-top: 2rem;">
      <button class="btn-primary" style="width: 100%; font-size: 1.2rem; background: var(--mt-green); padding: 15px;">Demander un Financement maTerre</button>
      <p style="text-align: center; font-size: 0.8rem; color: #888; margin-top: 10px;">
        ⚠️ L'investissement est soumis à un audit préalable du terrain (Module VÉRIFIER).
      </p>
    </div>
  </div>
</div>
